#!/usr/bin/env python3
from __future__ import annotations
import argparse,csv,hashlib,html,json,re
from pathlib import Path

PAGE='proof-mission-008.html'; HUB='proof-missions.html'
START='<!-- GOALOS_PROOF_MISSION_008_START -->'; END='<!-- GOALOS_PROOF_MISSION_008_END -->'
STYLE_START='<!-- GOALOS_PROOF_MISSION_008_STYLE_START -->'; STYLE_END='<!-- GOALOS_PROOF_MISSION_008_STYLE_END -->'
PROMO_START='<!-- GOALOS_PROOF_MISSION_008_PROMOTION_START -->'; PROMO_END='<!-- GOALOS_PROOF_MISSION_008_PROMOTION_END -->'
M7_END='<!-- GOALOS_PROOF_MISSION_007_END -->'

def fail(m): raise RuntimeError(m)
def load(p): return json.loads(Path(p).read_text(encoding='utf-8'))
def dump(p,v): p=Path(p); p.parent.mkdir(parents=True,exist_ok=True); p.write_text(json.dumps(v,indent=2,ensure_ascii=False)+'\n',encoding='utf-8')
def sha(p): return hashlib.sha256(Path(p).read_bytes()).hexdigest()
def esc(v): return html.escape(str(v),quote=True)

def validate(c,m):
 if c.get('missionId')!='GOALOS-PUBLIC-PROOF-MISSION-008' or c.get('sequence')!=8: fail('Mission 008 identity mismatch')
 if c.get('status')!='PROTOCOL_PUBLISHED_AWAITING_THREE_STEWARDSHIP_PROVEN_COVENANTS': fail('Mission 008 status mismatch')
 if len(c.get('optionalityTrial',{}).get('gates',[]))!=9: fail('Nine optionality gates required')
 if len(c.get('validators',[]))!=9: fail('Nine validators required')
 if len(c.get('proofRoute',[]))!=48 or len({x['contractName'] for x in c['proofRoute']})!=48: fail('48 distinct proof-route contracts required')
 if sum(x.get('share',0) for x in c.get('settlement',[]))!=100: fail('Settlement must total 100')
 if m.get('goalosCreatedContractCount')!=48 or m.get('verification',{}).get('verified')!=48 or m.get('verification',{}).get('failed')!=0: fail('Mainnet evidence mismatch')
 names={x['name'] for x in m.get('contracts',[])}
 if not {x['contractName'] for x in c['proofRoute']}<=names: fail('Unknown Mainnet route contract')
 if any(x in json.dumps(c).lower() for x in ('recursive.com','recursive org','recursive-style','named competitor')): fail('Named competitor reference prohibited')

def emblem():
 nodes=[('O0',310,42),('O1',495,100),('O2',590,265),('O3',555,455),('O4',405,575),('O5',215,575),('O6',65,455),('O7',30,265),('O8',125,100)]
 node_svg=''.join(f'<g><circle cx="{x}" cy="{y}" r="35"/><text x="{x}" y="{y+4}">{n}</text></g>' for n,x,y in nodes)
 lines=''.join(f'<path d="M310 310L{x} {y}"/>' for _,x,y in nodes)
 return f'''<svg class="of-emblem" viewBox="0 0 620 620" role="img" aria-label="The Open Future nine-gate optionality emblem"><defs><radialGradient id="ofcore"><stop stop-color="#fff"/><stop offset=".25" stop-color="#ffe7a8"/><stop offset=".55" stop-color="#68f2d0"/><stop offset="1" stop-color="#8a75ff"/></radialGradient><linearGradient id="ofline"><stop stop-color="#ffe7a8"/><stop offset=".46" stop-color="#68f2d0"/><stop offset="1" stop-color="#8a75ff"/></linearGradient><filter id="ofglow"><feGaussianBlur stdDeviation="6" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs><circle class="of-orbit" cx="310" cy="310" r="278"/><circle class="of-orbit inner" cx="310" cy="310" r="210"/><circle class="of-orbit inner2" cx="310" cy="310" r="142"/><g class="of-rays">{lines}</g><g class="of-nodes">{node_svg}</g><g filter="url(#ofglow)"><circle cx="310" cy="310" r="104" fill="url(#ofcore)"/><text class="of-core" x="310" y="284">THE</text><text class="of-core" x="310" y="320">OPEN</text><text class="of-core" x="310" y="356">FUTURE</text><text class="of-m8" x="310" y="396">M8</text></g></svg>'''

