def hub_page(c):
 missions=[
 ('001','The Proof Gradient','Where autonomous work earns the right to become capability.','proof-gradient-challenge.html'),
 ('002','The Ascension Protocol','Where proven capability learns to travel.','proof-mission-002.html'),
 ('003','The Capability Constellation','Where proven capabilities become a governed intelligence.','proof-mission-003.html'),
 ('004','The Sovereign Institution','Where governed intelligence learns to endure.','proof-mission-004.html'),
 ('005','The Interinstitutional Accord','Where sovereign institutions cooperate without surrendering sovereignty.','proof-mission-005.html'),
 ('006','The Long Horizon','Where governed intelligence proves it can remain faithful across generations.','proof-mission-006.html'),
 ('007','The Civilizational Covenant','Where continuity becomes stewardship—without sovereignty over humanity.','proof-mission-007.html'),
 ('008','The Open Future','Where stewardship proves it can preserve the freedom to become.','proof-mission-008.html')]
 cards=''.join(f'<article class="of-mission-card {"active" if num=="008" else ""}"><strong>PUBLIC PROOF MISSION {num}</strong><h2>{esc(title)}</h2><p>{esc(copy)}</p><a href="{href}">Enter mission →</a></article>' for num,title,copy,href in missions)
 return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>GoalOS Public Proof Missions 001–008</title>{css()}</head><body><main class="of-hub"><div class="of-shell"><div class="of-eyebrow">GoalOS AGIALPHA Ascension</div><h1>THE PUBLIC<br>PROOF MISSIONS</h1><p style="max-width:860px;font-size:1.15rem;line-height:1.75;color:#c8d6dc">Capability. Transfer. Composition. Institution. Accord. Continuity. Stewardship. Optionality. Eight protocols for turning autonomous work into governed, replayable, reversible institutional capability while preserving the freedom to become.</p><div class="of-hub-grid">{cards}</div><article class="of-mission-card" style="margin-top:1rem"><strong>MISSION 009 HORIZON</strong><h2>{esc(c['mission9']['title'])}</h2><p>{esc(c['mission9']['copy'])}</p><span class="of-status">HORIZON ONLY · NOT AUTHORIZED</span></article><p style="margin-top:2rem"><a class="of-btn" href="index.html">Return to GoalOS</a></p></div></main></body></html>'''

def home_style(): return f'''{STYLE_START}{css()}{STYLE_END}'''
def home_section():
 return f'''{START}<section class="of-home"><div class="of-home-in"><div><small>PUBLIC PROOF MISSION 008 · RADICAL OPTIONALITY</small><h2>THE <span>OPEN FUTURE</span></h2><p><strong>Where stewardship proves it can preserve the freedom to become.</strong> Mission 008 publishes a bounded protocol for deep uncertainty, plural values, reversible exploration, novel intelligence, future generations, planetary boundaries, independent challenge, constitutional fork, portable exit, rollback, archival continuity, and dignified dissolution.</p><div class="of-home-law">No optimization that closes the future. No irreversible commitment without plural consent, bounded trials, and rollback. No inherited value, authority, or memory without renewed human ratification.</div><div class="of-home-actions"><a href="{PAGE}">Enter Mission 008</a><a href="{HUB}">Open the Proof Missions</a></div></div><div class="of-home-portal"><i></i><i></i><i></i><div class="of-home-core">M8<br>OPTIONALITY</div></div></div></section>{END}'''

def replace_marked(t,s,e,r):
 if t.count(s)!=1 or t.count(e)!=1: fail(f'marker count mismatch: {s}')
 return re.sub(re.escape(s)+r'.*?'+re.escape(e),r,t,count=1,flags=re.S)

def inject_home(p):
 p=Path(p); raw=p.read_text(encoding='utf-8'); st=home_style(); sec=home_section()
 raw=replace_marked(raw,STYLE_START,STYLE_END,st) if STYLE_START in raw else raw.replace('</head>',st+'\n</head>',1)
 if START in raw: raw=replace_marked(raw,START,END,sec)
 elif M7_END in raw: raw=raw.replace(M7_END,M7_END+'\n'+sec,1)
 else: fail('Mission 007 homepage marker not found')
 p.write_text(raw,encoding='utf-8')

def promote_m7(p):
 p=Path(p); raw=p.read_text(encoding='utf-8')
 active=f'''{PROMO_START}<article class="cv-horizon"><strong>PUBLIC PROOF MISSION 008 · NOW PUBLISHED</strong><h2>The Open Future</h2><p>Mission 008 publishes the bounded protocol for radical optionality under deep uncertainty: reversible exploration, plural values, novel-intelligence admission, future-generation agency, ecological boundaries, irreversibility review, public challenge, fork, exit, rollback, renewal, and dissolution.</p><p><a class="cv-btn primary" href="proof-mission-008.html">Enter Mission 008</a></p></article>{PROMO_END}'''
 if PROMO_START in raw: raw=replace_marked(raw,PROMO_START,PROMO_END,active)
 else:
  raw,n=re.subn(r'<article class="cv-horizon"><strong>MISSION 008 HORIZON</strong>.*?</article>',active,raw,count=1,flags=re.S)
  if n!=1: fail('Mission 007 horizon not found')
 p.write_text(raw,encoding='utf-8')

def downloads(site,c,m):
 out=Path(site)/'downloads/proof-missions'; out.mkdir(parents=True,exist_ok=True); dump(out/'public-proof-mission-008.json',c)
 templates={
 'mission-008-open-future-charter-template.json':{'humanAuthorityRoots':[],'protectedValues':[],'optionSet':[],'stopConditions':[],'renewal':None,'status':'TEMPLATE_NOT_EVIDENCE'},
 'mission-008-optionality-ledger-template.json':{'options':[],'dependencies':[],'lockInRisks':[],'uncertainties':[],'abstentionTriggers':[],'status':'TEMPLATE_NOT_EVIDENCE'},
 'mission-008-irreversibility-register-template.json':{'actions':[],'irreversibilityClass':[],'consent':[],'recoveryReserves':[],'rollbackEvidence':[],'status':'TEMPLATE_NOT_EVIDENCE'},
 'mission-008-novel-intelligence-admission-template.json':{'candidate':None,'conformance':[],'authorityLimits':[],'evaluation':[],'challenge':[],'ratification':None,'status':'TEMPLATE_NOT_EVIDENCE'},
 'mission-008-fork-exit-rollback-template.json':{'forks':[],'exits':[],'rollbacks':[],'archives':[],'obligations':[],'finalDisposition':'NOT_SELECTED','status':'TEMPLATE_NOT_EVIDENCE'} }
 for name,v in templates.items(): v.update({'schemaVersion':'1.0','missionId':c['missionId']}); dump(out/name,v)
 by={x['name']:x for x in m['contracts']}
 with (out/'mission-008-proof-route.csv').open('w',newline='',encoding='utf-8') as f:
  w=csv.DictWriter(f,fieldnames=['sequence','stage','contract','address','purpose','etherscan_url']); w.writeheader()
  for x in c['proofRoute']:
   d=by[x['contractName']]; w.writerow({'sequence':x['sequence'],'stage':x['stage'],'contract':x['contractName'],'address':d['address'],'purpose':x['purpose'],'etherscan_url':d['etherscanUrl']})

def main():
 ap=argparse.ArgumentParser(); ap.add_argument('--site',default='site'); ap.add_argument('--content',default='content/proof-mission-008-open-future.json'); ap.add_argument('--mainnet',default='data/mainnet/v4.4.0-mainnet-2026-06-21.json'); a=ap.parse_args()
 site=Path(a.site); cp=Path(a.content); mp=Path(a.mainnet); c=load(cp); m=load(mp); validate(c,m)
 req=[site/'index.html',site/'proof-missions.html',site/'proof-gradient-challenge.html',site/'proof-mission-002.html',site/'proof-mission-003.html',site/'proof-mission-004.html',site/'proof-mission-005.html',site/'proof-mission-006.html',site/'proof-mission-007.html']
 miss=[str(x) for x in req if not x.is_file() or x.stat().st_size==0]
 if miss: fail('Build Missions 001–007 first: '+', '.join(miss))
 preserve=[site/'proof-gradient-challenge.html',site/'proof-mission-002.html',site/'proof-mission-003.html',site/'proof-mission-004.html',site/'proof-mission-005.html',site/'proof-mission-006.html']
 prior={x.name:sha(x) for x in preserve}
 (site/PAGE).write_text(page(c,m),encoding='utf-8'); (site/HUB).write_text(hub_page(c),encoding='utf-8'); inject_home(site/'index.html'); promote_m7(site/'proof-mission-007.html'); downloads(site,c,m)
 for x in preserve:
  if sha(x)!=prior[x.name]: fail(x.name+' changed unexpectedly')
 qa={'status':'PASS','missionId':c['missionId'],'proofRouteStages':48,'validatorQuorum':9,'optionalityGates':9,'mission001To006Preserved':True,'mission007HorizonPromoted':True,'publicNetworkTransactionSent':False,'contentSha256':sha(cp),'mainnetDataSha256':sha(mp)}
 dump(site/'qa/proof-mission-008-build.json',qa); print(json.dumps(qa,indent=2)); return 0
if __name__=='__main__': raise SystemExit(main())
